class CredentialManager(config: AwsConfig) {

  private var currentProvider: AwsCredentialsProvider = buildProvider(config.credentialMode)

  def buildProvider(mode: CredentialMode): AwsCredentialsProvider = mode match {
    case StaticCredentials(accessKey, secretKey) =>
      StaticCredentialsProvider.create(AwsBasicCredentials.create(accessKey, secretKey))

    case SessionCredentials(accessKey, secretKey, sessionToken) =>
      StaticCredentialsProvider.create(
        AwsSessionCredentials.create(accessKey, secretKey, sessionToken)
      )

    case ProfileCredentials(profileName) =>
      ProfileCredentialsProvider.create(profileName)

    case DefaultCredentials =>
      DefaultCredentialsProvider.create()

    case AssumeRoleCredentials(roleArn, sessionName) =>
      val stsClient = StsClient.builder()
        .region(config.region)
        .credentialsProvider(DefaultCredentialsProvider.create())
        .build()

      val assumeRoleResponse = stsClient.assumeRole(
        AssumeRoleRequest.builder()
          .roleArn(roleArn)
          .roleSessionName(sessionName)
          .durationSeconds(3600)
          .build()
      )

      val credentials = assumeRoleResponse.credentials()
      StaticCredentialsProvider.create(
        AwsSessionCredentials.create(
          credentials.accessKeyId(),
          credentials.secretAccessKey(),
          credentials.sessionToken()
        )
      )
  }

  def getProvider: AwsCredentialsProvider = currentProvider

  def rotateCredentials(newMode: CredentialMode): Unit = {
    currentProvider = buildProvider(newMode)
  }

  def validateCredentials(): Try[String] = Try {
    val stsClient = StsClient.builder()
      .region(config.region)
      .credentialsProvider(currentProvider)
      .build()

    val identity = stsClient.getCallerIdentity(GetCallerIdentityRequest.builder().build())
    stsClient.close()
    s"Authenticated as: ${identity.arn()}"
  }
}

