object AwsServiceApp extends App {

  // Example 1: Using default credentials
  val defaultConfig = AwsConfig(
    region = Region.US_EAST_1,
    credentialMode = DefaultCredentials
  )
  val defaultManager = new AwsServiceManager(defaultConfig)

  // Example 2: Using static credentials
  val staticConfig = AwsConfig(
    region = Region.US_WEST_2,
    credentialMode = StaticCredentials(
      accessKeyId = sys.env.getOrElse("AWS_ACCESS_KEY_ID", ""),
      secretAccessKey = sys.env.getOrElse("AWS_SECRET_ACCESS_KEY", "")
    )
  )
  val staticManager = new AwsServiceManager(staticConfig)

  // Example 3: Using profile credentials
  val profileConfig = AwsConfig(
    region = Region.EU_WEST_1,
    credentialMode = ProfileCredentials("my-profile")
  )

  // Example 4: Using assume role
  val assumeRoleConfig = AwsConfig(
    region = Region.US_EAST_1,
    credentialMode = AssumeRoleCredentials(
      roleArn = "arn:aws:iam::123456789012:role/MyRole",
      sessionName = "my-session"
    )
  )

  // Validate credentials
  defaultManager.validateAuthentication() match {
    case Success(identity) => println(s"Authentication successful: $identity")
    case Failure(ex) => println(s"Authentication failed: ${ex.getMessage}")
  }

  // S3 operations
  defaultManager.s3.listBuckets() match {
    case Success(buckets) => println(s"S3 Buckets: ${buckets.mkString(", ")}")
    case Failure(ex) => println(s"Failed to list buckets: ${ex.getMessage}")
  }

  defaultManager.s3.putObject("my-bucket", "test-key", "Hello, World!") match {
    case Success(_) => println("Object uploaded successfully")
    case Failure(ex) => println(s"Upload failed: ${ex.getMessage}")
  }

  defaultManager.s3.getObject("my-bucket", "test-key") match {
    case Success(content) => println(s"Object content: $content")
    case Failure(ex) => println(s"Get failed: ${ex.getMessage}")
  }

  // SQS operations
  defaultManager.sqs.sendMessage("https://sqs.us-east-1.amazonaws.com/123456789012/my-queue", "Test message") match {
    case Success(messageId) => println(s"Message sent: $messageId")
    case Failure(ex) => println(s"Send failed: ${ex.getMessage}")
  }

  defaultManager.sqs.receiveMessages("https://sqs.us-east-1.amazonaws.com/123456789012/my-queue") match {
    case Success(messages) =>
      messages.foreach { case (id, body, _) =>
        println(s"Message [$id]: $body")
      }
    case Failure(ex) => println(s"Receive failed: ${ex.getMessage}")
  }

  // DynamoDB operations
  defaultManager.dynamoDb.putItem("my-table", Map("id" -> "1", "name" -> "test", "value" -> "hello")) match {
    case Success(_) => println("Item put successfully")
    case Failure(ex) => println(s"Put failed: ${ex.getMessage}")
  }

  defaultManager.dynamoDb.getItem("my-table", Map("id" -> "1")) match {
    case Success(Some(item)) => println(s"Item: $item")
    case Success(None) => println("Item not found")
    case Failure(ex) => println(s"Get failed: ${ex.getMessage}")
  }

  // Rotate credentials at runtime
  defaultManager.switchCredentials(
    StaticCredentials("new-access-key", "new-secret-key")
  )
  println("Credentials rotated successfully")
}